import UIKit
import WebKit
import UserNotifications
import StoreKit
import AVFoundation

class WebContainerViewController: UIViewController, WKScriptMessageHandler, WKNavigationDelegate, UIImagePickerControllerDelegate, UINavigationControllerDelegate, SKPaymentTransactionObserver {

    private var webView: WKWebView!
    private let mobileURL = URL(string: "https://m.example.com")! // replace with actual URL

    override func viewDidLoad() {
        super.viewDidLoad()
        setupWebView()
        loadMobileSite()
        SKPaymentQueue.default().add(self)
    }

    deinit {
        SKPaymentQueue.default().remove(self)
        webView.configuration.userContentController.removeScriptMessageHandler(forName: "native")
    }

    private func setupWebView() {
        let contentController = WKUserContentController()
        contentController.add(self, name: "native")

        let config = WKWebViewConfiguration()
        config.userContentController = contentController
        config.preferences.javaScriptEnabled = true
        config.allowsInlineMediaPlayback = true

        webView = WKWebView(frame: .zero, configuration: config)
        webView.navigationDelegate = self
        webView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(webView)

        NSLayoutConstraint.activate([
            webView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            webView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            webView.topAnchor.constraint(equalTo: view.topAnchor),
            webView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }

    private func loadMobileSite() {
        webView.load(URLRequest(url: mobileURL))
    }

    // MARK: - WKScriptMessageHandler

    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard message.name == "native",
              let body = message.body as? [String: Any],
              let action = body["action"] as? String else { return }

        switch action {
        case "camera":
            presentCamera()
        case "pushPermission":
            requestPushPermission()
        case "purchase":
            if let productID = body["productId"] as? String {
                startPurchase(productID: productID)
            }
        default:
            break
        }
    }

    // MARK: - Camera

    private func presentCamera() {
        guard UIImagePickerController.isSourceTypeAvailable(.camera) else { return }
        AVCaptureDevice.requestAccess(for: .video) { granted in
            DispatchQueue.main.async {
                guard granted else { return }
                let picker = UIImagePickerController()
                picker.sourceType = .camera
                picker.delegate = self
                self.present(picker, animated: true)
            }
        }
    }

    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        picker.dismiss(animated: true) {
            if let image = info[.originalImage] as? UIImage,
               let data = image.jpegData(compressionQuality: 0.8) {
                let base64 = data.base64EncodedString()
                let js = "window.dispatchEvent(new CustomEvent('cameraResult', { detail: { image: '\(base64)' }}));"
                self.webView.evaluateJavaScript(js, completionHandler: nil)
            }
        }
    }

    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        picker.dismiss(animated: true)
    }

    // MARK: - Push Notifications

    private func requestPushPermission() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .sound, .badge]) { granted, _ in
            DispatchQueue.main.async {
                let js = "window.dispatchEvent(new CustomEvent('pushPermissionResult', { detail: { granted: \(granted) }}));"
                self.webView.evaluateJavaScript(js, completionHandler: nil)
            }
        }
    }

    // MARK: - In-App Purchases

    private func startPurchase(productID: String) {
        guard SKPaymentQueue.canMakePayments() else {
            let js = "window.dispatchEvent(new CustomEvent('purchaseError', { detail: { message: 'Purchases not allowed' }}));"
            webView.evaluateJavaScript(js, completionHandler: nil)
            return
        }
        let request = SKProductsRequest(productIdentifiers: [productID])
        request.delegate = self
        request.start()
    }

    // MARK: - SKPaymentTransactionObserver

    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                queue.finishTransaction(transaction)
                let js = "window.dispatchEvent(new CustomEvent('purchaseSuccess', { detail: { productId: '\(transaction.payment.productIdentifier)' }}));"
                webView.evaluateJavaScript(js, completionHandler: nil)
            case .failed:
                queue.finishTransaction(transaction)
                let reason = transaction.error?.localizedDescription ?? "Unknown error"
                let js = "window.dispatchEvent(new CustomEvent('purchaseError', { detail: { message: '\(reason)' }}));"
                webView.evaluateJavaScript(js, completionHandler: nil)
            default:
                break
            }
        }
    }
}

extension WebContainerViewController: SKProductsRequestDelegate {
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        guard let product = response.products.first else { return }
        SKPaymentQueue.default().add(SKPayment(product: product))
    }

    func request(_ request: SKRequest, didFailWithError error: Error) {
        let js = "window.dispatchEvent(new CustomEvent('purchaseError', { detail: { message: '\(error.localizedDescription)' }}));"
        webView.evaluateJavaScript(js, completionHandler: nil)
    }
}